from dataclasses import dataclass
from datetime import datetime

@dataclass
class DependencyRecord:
    name: str
    current_version: str
    latest_patched_version: str | None   # None if up to date
    cve_ids: list[str]                   # open CVEs affecting current version
    effective_severity: str              # highest effective severity across all CVEs
    last_scanned_at: datetime

@dataclass
class DependencyInventoryReport:
    scanned_at: datetime
    service: str
    environment: str         # "production", "staging"
    records: list[DependencyRecord]

    def action_required(self) -> list[DependencyRecord]:
        """Dependencies with open CVEs, sorted by severity."""
        severity_order = {"critical": 0, "high": 1, "medium": 2, "low": 3}
        flagged = [r for r in self.records if r.cve_ids]
        return sorted(flagged, key=lambda r: severity_order.get(r.effective_severity, 99))

    def critical_count(self) -> int:
        return sum(1 for r in self.records if r.effective_severity == "critical")

    def summary_line(self) -> str:
        flagged = self.action_required()
        return (
            f"{self.service} @ {self.environment} — "
            f"{len(self.records)} deps scanned, "
            f"{len(flagged)} with CVEs "
            f"({self.critical_count()} critical)"
        )

