from dataclasses import dataclass
from datetime import date, datetime

@dataclass
class PatchComplianceRecord:
    cve_id: str
    component: str
    effective_severity: str
    detected_at: datetime
    patched_at: datetime | None
    patch_deadline: datetime

    def is_overdue(self, as_of: datetime | None = None) -> bool:
        if self.patched_at is not None:
            return False   # already patched
        ref = as_of or datetime.utcnow()
        return ref > self.patch_deadline

    def sla_met(self) -> bool | None:
        """None if still open."""
        if self.patched_at is None:
            return None
        return self.patched_at <= self.patch_deadline

    def days_to_patch(self) -> float | None:
        if self.patched_at is None:
            return None
        return (self.patched_at - self.detected_at).total_seconds() / 86400

@dataclass
class MonthlySecurityPostureReport:
    report_month: date
    records: list[PatchComplianceRecord]

    def compliance_rate(self, severity: str) -> float:
        closed = [r for r in self.records if r.effective_severity == severity and r.patched_at]
        if not closed:
            return 1.0
        met = sum(1 for r in closed if r.sla_met())
        return met / len(closed)

    def open_by_severity(self) -> dict[str, int]:
        open_records = [r for r in self.records if r.patched_at is None]
        result: dict[str, int] = {}
        for r in open_records:
            result[r.effective_severity] = result.get(r.effective_severity, 0) + 1
        return result

    def overdue_records(self) -> list[PatchComplianceRecord]:
        return [r for r in self.records if r.is_overdue()]
